import * as React from 'react';

import { DayPicker } from 'react-day-picker';

import { Button } from '../button';
import { CalendarIcon } from '../icons';
import { Popover, PopoverContent, PopoverTrigger } from '../popover';
import { cn } from '../utils/cn';

type DatePickerProps = {
  selected?: Date;
  onSelect?: (date: Date | undefined) => void;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
};

/**
 * A date picker that composes Popover, Button, and react-day-picker v9.
 *
 * Opens a calendar popover when the trigger button is clicked.
 */
function DatePicker({
  selected,
  onSelect,
  placeholder = 'Pick a date',
  disabled = false,
  className,
}: DatePickerProps) {
  const [open, setOpen] = React.useState(false);

  function handleSelect(date: Date | undefined) {
    onSelect?.(date);
    setOpen(false);
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <div data-slot="date-picker" className={cn(className)}>
        <PopoverTrigger asChild>
          <Button
            variant="solid"
            color="default"
            disabled={disabled}
            className={cn(
              'justify-start text-left font-normal',
              !selected && 'text-muted-foreground'
            )}
          >
            <CalendarIcon />
            <span>{selected ? selected.toLocaleDateString() : placeholder}</span>
          </Button>
        </PopoverTrigger>
        <PopoverContent className="w-auto p-3" align="start">
          <DayPicker
            mode="single"
            selected={selected}
            onSelect={handleSelect}
            classNames={{
              root: 'text-foreground',
              months: 'flex flex-col',
              month: 'space-y-4',
              month_caption: 'flex justify-center pt-1 relative items-center',
              caption_label: 'text-sm font-medium',
              nav: 'flex items-center gap-1',
              button_previous:
                'inline-flex items-center justify-center rounded-sm h-7 w-7 bg-transparent hover:bg-surface text-foreground',
              button_next:
                'inline-flex items-center justify-center rounded-sm h-7 w-7 bg-transparent hover:bg-surface text-foreground',
              month_grid: 'w-full border-collapse space-y-1',
              weekdays: 'flex',
              weekday:
                'text-muted-foreground rounded-sm w-9 font-normal text-[0.8rem]',
              week: 'flex w-full mt-2',
              day: 'h-9 w-9 text-center text-sm relative flex items-center justify-center rounded-sm hover:bg-surface',
              day_button:
                'h-9 w-9 p-0 font-normal inline-flex items-center justify-center',
              selected:
                'bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground',
              today: 'font-bold',
              outside: 'text-muted-foreground opacity-50',
              disabled: 'text-muted-foreground opacity-50',
            }}
          />
        </PopoverContent>
      </div>
    </Popover>
  );
}

export { DatePicker };
export type { DatePickerProps };
